// One system per loop
const row = items[0].json;

// ---------- Parse bodies list ----------

let bodies = [];
if (Array.isArray(row.bodies_list)) {
  bodies = row.bodies_list;
} else if (typeof row.bodies_list === 'string') {
  try {
    bodies = JSON.parse(row.bodies_list);
  } catch (e) {
    bodies = [];
  }
} else if (row.bodies_list && typeof row.bodies_list === 'object') {
  bodies = Object.values(row.bodies_list);
}

bodies = (bodies || [])
  .map(b => String(b || '').trim())
  .filter(b => b.length > 0);
bodies.sort((a, b) => a.localeCompare(b, undefined, { sensitivity: 'base' }));

const bodiesTotal = Number(row.bodies_total ?? bodies.length) || 0;

// ---------- Parse major locations list ----------

let majorLocations = [];
if (Array.isArray(row.major_locations_list)) {
  majorLocations = row.major_locations_list;
} else if (typeof row.major_locations_list === 'string') {
  try {
    majorLocations = JSON.parse(row.major_locations_list);
  } catch (e) {
    majorLocations = [];
  }
} else if (row.major_locations_list && typeof row.major_locations_list === 'object') {
  majorLocations = Object.values(row.major_locations_list);
}

majorLocations = (majorLocations || [])
  .map(l => String(l || '').trim())
  .filter(l => l.length > 0);
majorLocations.sort((a, b) => a.localeCompare(b, undefined, { sensitivity: 'base' }));

const mlocsTotal = Number(row.major_locations_total ?? majorLocations.length) || 0;

// ---------- Shared header ----------

const headerLines = [];

headerLines.push(`# ${row.name}`);
headerLines.push('');

headerLines.push(`- **UEX System ID:** ${row.uex_system_id || 'N/A'}`);
headerLines.push(`- **Code:** ${row.system_code || 'N/A'}`);
headerLines.push(`- **Status:** ${row.is_available_live === '1' ? 'Live' : 'Planned / Inactive'}`);
headerLines.push(`- **Bodies (planets + moons):** ${bodiesTotal}`);
headerLines.push(`- **Major Locations:** ${mlocsTotal}`);
headerLines.push('');

// ---------- Helper for summary list selection ----------

function buildSummaryList(fullList, total) {
  if (total <= 5) {
    return {
      shown: [...fullList],
      suffix: '',
    };
  }
  const shown = fullList.slice(0, 5);
  const suffix = ` (${shown.length} of ${total})`;
  return { shown, suffix };
}

// ---------- SUMMARY VERSION ----------

const summaryLines = [...headerLines];

summaryLines.push(`## Bodies (Planets & Moons)`);
summaryLines.push('');
summaryLines.push('> _Note: Lists below are unordered and not ranked._');
summaryLines.push('');

let { shown: bodiesShown, suffix: _bodySuffix } =
  buildSummaryList(bodies, bodiesTotal);

if (bodiesShown.length === 0) {
  summaryLines.push('_No active bodies recorded for this system._');
} else {
  for (const name of bodiesShown) {
    summaryLines.push(`- ${name}`);
  }
  if (bodiesTotal > bodiesShown.length) {
    summaryLines.push('Ã¢â‚¬Â¦ and more');
  }
}

summaryLines.push('');
let { shown: mlocsShown, suffix: mlocSuffix } =
  buildSummaryList(majorLocations, mlocsTotal);

summaryLines.push(`## Major Locations${mlocSuffix}`);
summaryLines.push('');
summaryLines.push('> _Note: Lists below are unordered and not ranked._');
summaryLines.push('');

if (mlocsShown.length === 0) {
  summaryLines.push('_No major locations recorded for this system._');
} else {
  for (const name of mlocsShown) {
    summaryLines.push(`- ${name}`);
  }
  if (mlocsTotal > mlocsShown.length) {
    summaryLines.push('Ã¢â‚¬Â¦ and more');
  }
}

// ---------- DETAILED VERSION ----------

const detailedLines = [...headerLines];

detailedLines.push(`## Bodies (Planets & Moons)`);
detailedLines.push('');
detailedLines.push('> _Detailed view. Lists below are unordered and not ranked._');
detailedLines.push('');

if (bodies.length === 0) {
  detailedLines.push('_No active bodies recorded for this system._');
} else {
  for (const name of bodies) {
    detailedLines.push(`- ${name}`);
  }
}

detailedLines.push('');
detailedLines.push(`## Major Locations`);
detailedLines.push('');
detailedLines.push('> _Detailed view. Lists below are unordered and not ranked._');
detailedLines.push('');

if (majorLocations.length === 0) {
  detailedLines.push('_No major locations recorded for this system._');
} else {
  for (const name of majorLocations) {
    detailedLines.push(`- ${name}`);
  }
}

// ---------- Slug + file paths ----------

const slug = (row.slug || row.name)
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-|-$/g, '');

const filePathSummary  = `/RAG/KB/systems/${slug}.md`;
const filePathDetailed = `/RAG/KB/systems/${slug}_detailed.md`;

return [
  {
    json: {
      system_id: row.id,
      slug,
      name: row.name,

      markdown_summary: summaryLines.join('\n'),
      filePath_summary: filePathSummary,

      markdown_detailed: detailedLines.join('\n'),
      filePath_detailed: filePathDetailed,
    },
  },
];

